        val available = j - i
        val take = minOf(available.toLong(), maxToActivate)
        // Take the top 'take' elements from i to j-1 (sorted by value descending)
        val sortedSubList = indices.subList(i, j).sortedByDescending { value[it] }
        for (k in 0 until take.toInt()) {
